@GwtCompatible
final class WellBehavedMap<K, V> extends ForwardingMap<K, V> {
  private final Map<K, V> delegate;
  private Set<Entry<K, V>> entrySet;

  private WellBehavedMap(Map<K, V> delegate) {
    this.delegate = delegate;
  }

  /**
   * Wraps the given map into a {@code WellBehavedEntriesMap}, which
   * intercepts its {@code entrySet()} method by taking the
   * {@code Set<K> keySet()} and transforming it to
   * {@code Set<Entry<K, V>>}. All other invocations are delegated as-is.
   */
  static <K, V> WellBehavedMap<K, V> wrap(Map<K, V> delegate) {
    return new WellBehavedMap<K, V>(delegate);
  }

  @Override protected Map<K, V> delegate() {
    return delegate;
  }

  @Override public Set<Entry<K, V>> entrySet() {
    Set<Entry<K, V>> es = entrySet;
    if (es != null) {
      return es;
    }
    return entrySet = new EntrySet();
  }

  private final class EntrySet extends AbstractSet<Entry<K, V>> {
    @Override public int size() {
      return delegate.size();
    }

    @Override public Iterator<Entry<K, V>> iterator() {
      return transform(keySet().iterator(),
          new Function<K, Entry<K, V>>() {
            @Override public Entry<K, V> apply(final K key) {
              return new AbstractMapEntry<K, V>() {
                @Override public K getKey() {
                  return key;
                }
                @Override public V getValue() {
                  return get(key);
                }
                @Override public V setValue(V value) {
                  return put(key, value);
                }
              };
            }
          });
    }

    @Override public boolean contains(Object o) {
      if (!(o instanceof Entry)) {
        return false;
      }
      Entry<?, ?> entry = (Entry<?, ?>) o;
      Object targetKey = entry.getKey();
      Object targetValue = entry.getValue();
      if (!containsKey(targetKey)) {
        return false;
      }
      return Objects.equal(get(targetKey), targetValue);
    }

    @Override public boolean remove(Object o) {
      if (contains(o)) {
        Entry<?, ?> entry = (Entry<?, ?>) o;
        WellBehavedMap.this.remove(entry.getKey());
        return true;
      }
      return false;
    }
  }
}
